// ---------------------------------------------------------------------------
// 7. Daily insight generation — click generate → POST → poll → completed
// ---------------------------------------------------------------------------

describe('AI Coach page — Daily insight generation flow', () => {
  it('clicking generate → POSTs daily endpoint → shows completed insight', () => {
    cy.setupApiAuthCookies()
    stubRtUsers()
    stubDashboard()
    stubAnomalies()
    stubWeeklyReview()
    stubUpcomingRaces()

    // Initial fetch: no insight
    cy.intercept('GET', `${AI_LIST_EP}*type=daily*`, {
      statusCode: 200,
      body: { data: [] },
    }).as('getDailyEmpty')

    cy.viewport(1280, 900)
    cy.visit(PAGE_URL)
    cy.wait('@getDashboard')
    cy.wait('@getDailyEmpty')

    cy.get(`#${IDS.daily_insight_card}`).scrollIntoView()
    cy.get(`#${IDS.daily_insight_generate_btn}`).should('be.visible')

    // Stub POST endpoint
    cy.intercept('POST', `${DAILY_EP}`, {
      statusCode: 200,
      body: { queued: true, message: 'Daily insight queued' },
    }).as('postDaily')

    // After POST, handleGenerate sets insight to { status: 'pending' } which triggers
    // startPolling(). The poll fires every 8 seconds — the wait timeout must exceed that.
    cy.intercept('GET', `${AI_LIST_EP}*type=daily*`, {
      statusCode: 200,
      body: { data: [completedDailyInsight] },
    }).as('getDailyCompleted')

    cy.get(`#${IDS.daily_insight_generate_btn}`).click()
    cy.wait('@postDaily')
    // Poll interval is 8 s — allow 15 s for the first poll to arrive
    cy.wait('@getDailyCompleted', { timeout: 15000 })

    cy.get(`#${IDS.daily_insight_card}`).within(() => {
      cy.contains('Your recovery is on track').should('be.visible')
    })
  })
})

