describe('AI Coach page — Daily insight follow-up inline response', () => {
  beforeEach(() => {
    cy.setupApiAuthCookies()
    stubRtUsers()
    stubDashboard()
    stubAnomalies()
    stubWeeklyReview()
    stubUpcomingRaces()
    stubDailyInsight(completedInsightWithTags)

    cy.intercept('POST', `${FOLLOWUP_EP}`, {
      statusCode: 200,
      body: { content: 'Run easy for 30 minutes at Zone 2.' },
    }).as('postFollowUp')

    cy.viewport(1280, 900)
    cy.visit(PAGE_URL)
    cy.wait('@getDashboard')
    cy.get(`#${IDS.daily_insight_card}`).scrollIntoView()
  })

  it('follow-up section appears after submitting a question', () => {
    cy.get(`#${IDS.daily_insight_ask_coach}`).within(() => {
      cy.get('input').type('What should I do tomorrow?')
    })
    cy.get(`#${IDS.daily_insight_ask_btn}`).click()
    cy.wait('@postFollowUp')

    cy.get(`#${IDS.daily_insight_follow_up}`).should('be.visible')
  })

  it('follow-up section shows the submitted question as label', () => {
    cy.get(`#${IDS.daily_insight_ask_coach}`).within(() => {
      cy.get('input').type('What should I do tomorrow?')
    })
    cy.get(`#${IDS.daily_insight_ask_btn}`).click()
    cy.wait('@postFollowUp')

    cy.get(`#${IDS.daily_insight_follow_up}`).within(() => {
      cy.contains('What should I do tomorrow?').should('be.visible')
    })
  })

  it('shows the AI response text after loading', () => {
    cy.get(`#${IDS.daily_insight_ask_coach}`).within(() => {
      cy.get('input').type('Recommended zone?')
    })
    cy.get(`#${IDS.daily_insight_ask_btn}`).click()
    cy.wait('@postFollowUp')

    cy.get(`#${IDS.daily_insight_follow_up}`).within(() => {
      cy.contains('Run easy for 30 minutes at Zone 2.').should('be.visible')
    })
  })

  it('shows error state when follow-up POST returns 500', () => {
    cy.intercept('POST', `${FOLLOWUP_EP}`, {
      statusCode: 500,
      body: { error: 'Internal server error' },
    }).as('postFollowUpError')

    cy.get(`#${IDS.daily_insight_ask_coach}`).within(() => {
      cy.get('input').type('Will this fail?')
    })
    cy.get(`#${IDS.daily_insight_ask_btn}`).click()
    cy.wait('@postFollowUpError')

    cy.get(`#${IDS.daily_insight_follow_up}`).within(() => {
      cy.contains('Could not get a response').should('be.visible')
    })
  })

  it('dismiss button clears the follow-up section', () => {
    cy.get(`#${IDS.daily_insight_ask_coach}`).within(() => {
      cy.get('input').type('Any tips?')
    })
    cy.get(`#${IDS.daily_insight_ask_btn}`).click()
    cy.wait('@postFollowUp')

    cy.get(`#${IDS.daily_insight_follow_up}`).should('be.visible')
    cy.get(`#${IDS.daily_insight_follow_up}`).within(() => {
      cy.get('button[aria-label="Clear follow-up"]').click()
    })
    cy.get(`#${IDS.daily_insight_follow_up}`).should('not.exist')
  })
})

